import { describe, expect, it } from 'vitest';
import {
  observationToProcessClock,
  buildClockTopology,
  topologyDelta,
} from './clock-topology-coordinator';
import type { ClockObservation } from './clock-topology-coordinator';

// ─── Fixtures ───────────────────────────────────────────────────────

const sfObs: ClockObservation = {
  pidId: 'pid:sf',
  label: 'SF Edge',
  colo: 'SFO',
  clockPLo: 1000,
  rttMs: 0.5,
  phase: 'active',
  requestRate: 150,
};

const tokyoObs: ClockObservation = {
  pidId: 'pid:tokyo',
  label: 'Tokyo Edge',
  colo: 'NRT',
  clockPLo: 1000,
  rttMs: 85,
  phase: 'active',
  requestRate: 200,
};

const londonObs: ClockObservation = {
  pidId: 'pid:london',
  label: 'London Edge',
  colo: 'LHR',
  clockPLo: 1000,
  rttMs: 70,
  phase: 'idle',
  requestRate: 0,
};

const sydneyObs: ClockObservation = {
  pidId: 'pid:sydney',
  label: 'Sydney Edge',
  colo: 'SYD',
  clockPLo: 1000,
  rttMs: 120,
  phase: 'active',
  requestRate: 80,
};

const unknownObs: ClockObservation = {
  pidId: 'pid:unknown',
  label: 'Unknown Edge',
  colo: 'XYZ',
  clockPLo: 1000,
  rttMs: 50,
  phase: 'active',
  requestRate: 10,
};

// ─── observationToProcessClock ──────────────────────────────────────

describe('observationToProcessClock', () => {
  it('converts a known colo to a ProcessClock', () => {
    const clock = observationToProcessClock(sfObs);
    expect(clock).not.toBeNull();
    expect(clock!.id).toBe('pid:sf');
    expect(clock!.label).toBe('SF Edge');
    expect(clock!.location.lat).toBeCloseTo(37.62, 1);
    expect(clock!.location.lon).toBeCloseTo(-122.38, 1);
    expect(clock!.phase).toBe('active');
    expect(clock!.requestRate).toBe(150);
  });

  it('returns null for an unknown colo', () => {
    const clock = observationToProcessClock(unknownObs);
    expect(clock).toBeNull();
  });
});

// ─── buildClockTopology ─────────────────────────────────────────────

describe('buildClockTopology', () => {
  const allObs = [sfObs, tokyoObs, londonObs, sydneyObs];

  it('produces correct node count', () => {
    const mesh = buildClockTopology(allObs);
    expect(mesh.clocks.length).toBe(4);
  });

  it('produces N*(N-1)/2 edges for N nodes', () => {
    const mesh = buildClockTopology(allObs);
    const n = mesh.clocks.length;
    expect(mesh.edges.length).toBe((n * (n - 1)) / 2);
  });

  it('silently drops observations with unknown colos', () => {
    const mesh = buildClockTopology([...allObs, unknownObs]);
    expect(mesh.clocks.length).toBe(4);
  });

  it('classifies SF-to-Tokyo edge as VENT at 1ms tolerance', () => {
    const mesh = buildClockTopology(allObs, 1);
    const sfTokyoEdge = mesh.edges.find(
      e =>
        (e.fromId === 'pid:sf' && e.toId === 'pid:tokyo') ||
        (e.fromId === 'pid:tokyo' && e.toId === 'pid:sf'),
    );
    expect(sfTokyoEdge).toBeDefined();
    expect(sfTokyoEdge!.edgeType).toBe('VENT');
  });
});

// ─── topologyDelta ──────────────────────────────────────────────────

describe('topologyDelta', () => {
  it('detects added nodes', () => {
    const prev = buildClockTopology([sfObs, tokyoObs]);
    const next = buildClockTopology([sfObs, tokyoObs, londonObs]);
    const delta = topologyDelta(prev, next);
    expect(delta.addedNodes).toContain('pid:london');
    expect(delta.removedNodes.length).toBe(0);
  });

  it('detects removed nodes', () => {
    const prev = buildClockTopology([sfObs, tokyoObs, londonObs]);
    const next = buildClockTopology([sfObs, tokyoObs]);
    const delta = topologyDelta(prev, next);
    expect(delta.removedNodes).toContain('pid:london');
    expect(delta.addedNodes.length).toBe(0);
  });

  it('detects promoted edges when tolerance increases', () => {
    // At 1ms tolerance, SF-Tokyo is VENT (>1ms propagation)
    const prev = buildClockTopology([sfObs, tokyoObs], 1);
    // At 1000ms tolerance, SF-Tokyo becomes PROCESS
    const next = buildClockTopology([sfObs, tokyoObs], 1000);
    const delta = topologyDelta(prev, next);
    expect(delta.promotedEdges.length).toBeGreaterThan(0);
    expect(delta.demotedEdges.length).toBe(0);
  });

  it('detects demoted edges when tolerance decreases', () => {
    const prev = buildClockTopology([sfObs, tokyoObs], 1000);
    const next = buildClockTopology([sfObs, tokyoObs], 1);
    const delta = topologyDelta(prev, next);
    expect(delta.demotedEdges.length).toBeGreaterThan(0);
    expect(delta.promotedEdges.length).toBe(0);
  });

  it('reflects connectivity change in physicalOrderingFraction delta', () => {
    const prev = buildClockTopology([sfObs, tokyoObs], 1);
    const next = buildClockTopology([sfObs, tokyoObs], 1000);
    const delta = topologyDelta(prev, next);
    // Promoting from VENT to PROCESS increases connectivity
    expect(delta.connectivityChange).toBeGreaterThan(0);
  });
});
